    def evaluate(assignment, clauses):
        for clause in clauses:
            satisfied = False
            for literal in clause:
                var = abs(literal) - 1
                value = assignment[var] if literal > 0 else not assignment[var]
                if value:
                    satisfied = True
                    break
            if not satisfied:
                return False
        return True

    # 2^n kombinasiyanı yoxlayır
    for i in range(1 << n):
        assignment = [(i >> j) & 1 == 1 for j in range(n)]
        if evaluate(assignment, clauses):
            return True
    return False

