import java.util.*;

class SATSolver {
    static boolean isSatisfiable(int[][] clauses, int n) {
        // Sadələşdirilmiş SAT problemi: Bütün kombinasiyaları yoxlayır
        class Evaluator {
            static boolean evaluate(boolean[] assignment, int[][] clauses) {
                for (int[] clause : clauses) {
                    boolean satisfied = false;
                    for (int literal : clause) {
                        int var = Math.abs(literal) - 1;
                        boolean value = literal > 0 ? assignment[var] : !assignment[var];
                        if (value) {
                            satisfied = true;
                            break;
                        }
                    }
                    if (!satisfied) return false;
                }
                return true;
            }
        }

        // 2^n kombinasiyanı yoxlayır
        for (int i = 0; i < (1 << n); i++) {
            boolean[] assignment = new boolean[n];
            for (int j = 0; j < n; j++) {
                assignment[j] = ((i >> j) & 1) == 1;
            }
            if (Evaluator.evaluate(assignment, clauses)) return true;
        }
        return false;
    }

    public static void main(String[] args) {
