#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

bool evaluate(bool* assignment, int** clauses, int clauseCount, int literalCount) {
    for (int i = 0; i < clauseCount; i++) {
        bool satisfied = false;
        for (int j = 0; j < literalCount; j++) {
            if (clauses[i][j] == 0) break;
            int var = abs(clauses[i][j]) - 1;
            bool value = clauses[i][j] > 0 ? assignment[var] : !assignment[var];
            if (value) {
                satisfied = true;
                break;
            }
        }
        if (!satisfied) return false;
    }
    return true;
}

bool isSatisfiable(int** clauses, int n, int clauseCount, int literalCount) {
    // 2^n kombinasiyanı yoxlayır
    bool* assignment = (bool*)malloc(n * sizeof(bool));
    for (int i = 0; i < (1 << n); i++) {
        for (int j = 0; j < n; j++) {
            assignment[j] = (i >> j) & 1;
        }
        if (evaluate(assignment, clauses, clauseCount, literalCount)) {
            free(assignment);
            return true;
        }
    }
    free(assignment);
    return false;
}

int main() {
    int clauses[3][2] = {{1, -2}, {-1, 3}, {2, -3}};
    int* clausesPtr[3] = {clauses[0], clauses[1], clauses[2]};
    bool result = isSatisfiable(clausesPtr, 3, 3, 2);
    printf("Satisfiable: %s\n", result ? "true" : "false");
    return 0;
}
// Çıxış: Satisfiable: true

