bool isSatisfiable(const std::vector<std::vector<int>>& clauses, int n) {
    // 2^n kombinasiyanı yoxlayır
    for (int i = 0; i < (1 << n); i++) {
        std::vector<bool> assignment(n, false);
        for (int j = 0; j < n; j++) {
            assignment[j] = (i >> j) & 1;
        }
        if (evaluate(assignment, clauses)) return true;
    }
    return false;
}

int main() {
    std::vector<std::vector<int>> clauses = {{1, -2}, {-1, 3}, {2, -3}};
    bool result = isSatisfiable(clauses, 3);
    std::cout << "Satisfiable: " << (result ? "true" : "false") << std::endl;
    return 0;
}
// Çıxış: Satisfiable: true
